import{_ as a,o as e,c as o,ag as r}from"./chunks/framework.wqPkq5Rj.js";const u=JSON.parse('{"title":"邀请你的同事一起来","description":"","frontmatter":{},"headers":[],"relativePath":"setup/invite.md","filePath":"setup/invite.md","lastUpdated":1777169627000}'),i={name:"setup/invite.md"};function l(n,t,s,d,h,p){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="邀请你的同事一起来" tabindex="-1">邀请你的同事一起来 <a class="header-anchor" href="#邀请你的同事一起来" aria-label="Permalink to &quot;邀请你的同事一起来&quot;">​</a></h1><p>Moxt 是一个团队工具。你一个人用，能感受到它一部分的价值。但当你的同事也在里面工作，AI 能看到所有人的上下文——那才是它真正变强的时候。</p><p>发出第一封邀请，是你们团队 AI 飞轮开始转动的那一刻。</p><hr><h2 id="怎么邀请" tabindex="-1">怎么邀请 <a class="header-anchor" href="#怎么邀请" aria-label="Permalink to &quot;怎么邀请&quot;">​</a></h2><ol><li>点击左侧边栏顶部的下拉菜单</li><li>选择「设置」→ 「成员」→「邀请成员」</li><li>输入同事的邮箱</li><li>发送邀请</li></ol><p>对方会收到一封邮件，点击链接后直接进入你们的团队工作空间。</p><p>你还可以通过「设置」→ 「成员」→「复制邀请链接」，将链接发送给群组或任意想要邀请的同事，对方访问链接点击加入就可以进入你们的团队工作空间。</p><hr><h2 id="邀请谁先来" tabindex="-1">邀请谁先来？ <a class="header-anchor" href="#邀请谁先来" aria-label="Permalink to &quot;邀请谁先来？&quot;">​</a></h2><p>不需要等所有人都准备好再一起来。建议先邀请 1-2 个最常需要协作的同事，让你们先跑起来。</p><p>通常最有价值的第一批人：</p><ul><li><strong>经常一起写文档的人</strong>——他们会立刻感受到 momo 在共同文档上的价值</li><li><strong>负责整理信息的人</strong>——日报、周报、会议纪要，AI 可以替他们完成大量重复劳动</li><li><strong>需要经常找你同步进展的人</strong>——空间里有所有更新，他们自己就能找到答案</li></ul><hr><h2 id="邀请之后可以做的第一件事" tabindex="-1">邀请之后可以做的第一件事 <a class="header-anchor" href="#邀请之后可以做的第一件事" aria-label="Permalink to &quot;邀请之后可以做的第一件事&quot;">​</a></h2><p>同事进来之后，让他们先做一件事：<strong>和 momo 打个招呼，告诉它自己是谁</strong>。</p><p>可以直接发这句话给他们：</p><blockquote><p>&quot;打开 Moxt 之后，在右侧找到 momo，发给它这句话：&#39;我是 [你的名字]，负责 [你的职责]，以后我们一起工作。&#39;然后看看它怎么回应你。&quot;</p></blockquote><p>这是最好的第一次体验——不是学会怎么用，而是感受到它把你当一个真实的人在认识。</p><hr><h2 id="关于权限" tabindex="-1">关于权限 <a class="header-anchor" href="#关于权限" aria-label="Permalink to &quot;关于权限&quot;">​</a></h2><table tabindex="0"><thead><tr><th>角色</th><th>权限</th></tr></thead><tbody><tr><td><strong>管理员</strong></td><td>管理成员、修改工作空间设置、管理积分与付款</td></tr><tr><td><strong>成员</strong></td><td>访问和编辑工作空间的内容</td></tr></tbody></table><p>工作空间中的个人空间是私有的——你的同事看不到你的个人文件夹，就像你们各自有一张独立的工作桌。</p>',23)])])}const _=a(i,[["render",l]]);export{u as __pageData,_ as default};
